from typing import Optional

def cloneGraph(node: Optional[object]) -> Optional[object]:
    if node is None:
        return None

    visited: dict = {}

    def dfs(n: object) -> object:
        if n in visited:
            return visited[n]
        # Assume Node has .val and .neighbors attributes
        clone = type(n)(n.val)  # Node(n.val)
        visited[n] = clone
        for neighbor in n.neighbors:
            clone.neighbors.append(dfs(neighbor))
        return clone

    return dfs(node)
